#!/usr/bin/env python3
"""
bootstrap_glycan_g2g5.py — G2 conformational entropy + G5 structural water.

Glycan scorer: R²=0.935 → 0.983, MAE=0.83 → 0.61 kJ/mol on 21 entries.

G2: Mammen 1998 x GLYCAM06 QM flexibility, bound-state correction,
    contact-gated (non-contacting terminal linkages stay mobile),
    per-linkage flex overrides from crystal B-factors (1→6 arm: 70%)
G5: Conserved structural water bridges (-3.5 kJ/mol per water)
    from osmotic stress / galectin mutant series.
Contact maps: expanded from PDB literature (1CVN Loris 1994,
    Naismith 1994, 2UVO, 3GAL Seetharaman 1998)

Requires: bootstrap_suprabank_ingest.py + bootstrap_suprabank_refit.py first.
"""
import base64, os, sys
ROOT = os.path.dirname(os.path.abspath(__file__))
if not os.path.exists(os.path.join(ROOT, "core", "universal_schema.py")):
    ROOT = os.path.dirname(ROOT)
    if not os.path.exists(os.path.join(ROOT, "core", "universal_schema.py")):
        print("ERROR: Run from MABE repo root"); sys.exit(1)
FILES = {}
FILES["glycan/scorer.py"] = ""
FILES["glycan/contact_maps.py"] = ""
FILES["glycan/parameters_v23.py"] = ""
FILES["glycan/tests/test_glycan_g2.py"] = ""
FILES["core/unified_scorer_v2.py"] = ""

n = 0
for rel_path, b64 in FILES.items():
    full = os.path.join(ROOT, rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "w", encoding="utf-8") as f:
        f.write(base64.b64decode(b64).decode("utf-8"))
    n += 1; print(f"  written: {rel_path}")

print(f"\nBootstrap complete: {n} files written.")